@azaroth42 asked if I could doublecheck this with the ruby JSON-LD library, so here's a ruby version of this code:

```ruby
require "linkeddata"

ctxtjs = {
  "@context" => {
    "ns" => "http://example.com/ns/",
    "hasList" => {"@id" => "ns:hasList", "@type" => "@id", "@container" => "@list"},
    "ref" => {"@id" => "ns:ref", "@type" => "@id"}
  } 
}

doc = {
  "@context" => ctxtjs['@context'],
  "@id" => "http://top/1",
  "@type" => "ns:A",
  "hasList" => [
    {
      "@id" => "http://child/1", 
      "@type" => "ns:B", 
      "ref" => "ns:something"
    },
    {
      "@id" => "http://child/2", 
      "@type" => "ns:B", 
      "ref" => "ns:something"
    }
  ]
}

framejs = {
  "@context" => ctxtjs['@context'],
  "@type" => "ns:A",
  "hasList" => [{
    "@type" => "ns:B"
  }]
}

results =  JSON::LD::API.frame(doc, framejs)
puts JSON.pretty_generate results
```

