            for input_num, in_shp in enumerate(in_shps):
                if out_shp != in_shp and in_shp == 1:
                    inputs[input_num] = T.addbroadcast(inputs[input_num], axis)
        output = None
        for input in inputs:
            if output is not None:
                output = self.merge_function(output, input)
            else:
