The kwargs passed to a ``post_generation`` declaration have to start with the name of the field.

It should work if you rewrite it as:
```python
class ManagerFactory(UserFactory):
    class Meta:
        model = User
        excluded = ('org', )

    last_name = "Manager"

    @factory.lazy_attribute
    def first_name(self):
        return 'Bookstore {}'.format(self.org.short_name)

    # Pass down the 'org' to the 'post' section
    post__org = factory.SelfAttribute('org')

    @factory.post_generation
    def post(self, create, extracted, **kwargs):
        if not create:
            return

        if kwargs.get('org'):
            OrgMember.objects.create(org=kwargs.get('org'), user=self, access=OrgMemberAccess.objects.get(type=accounts_constants.MANAGER))

